using HaCreator.MapEditor;using HaCreator.MapEditor.Instance.Shapes;using HaCreator.MapEditor.UndoRedo;using System;using System.Collections.Generic;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class RopeInstanceEditor:EditorBase{public RopeAnchor item;public RopeInstanceEditor(RopeAnchor item){InitializeComponent();this.item=item;InstanceEditorDialogSupport.SetInt(xInput,item.X);InstanceEditorDialogSupport.SetInt(yInput,item.Y);ufBox.IsChecked=item.ParentRope.uf;ladderBox.IsChecked=item.ParentRope.ladder;pathLabel.Text=HaCreatorStateManager.CreateItemDescription(item);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){lock(item.Board.ParentControl){int x=InstanceEditorDialogSupport.GetInt(xInput,item.X),y=InstanceEditorDialogSupport.GetInt(yInput,item.Y);List<UndoRedoAction> a=new();if(x!=item.X||y!=item.Y){a.Add(UndoRedoManager.ItemMoved(item,new Microsoft.Xna.Framework.Point(item.X,item.Y),new Microsoft.Xna.Framework.Point(x,y)));item.Move(x,y);}if(a.Count>0)item.Board.UndoRedoMan.AddUndoBatch(a);item.ParentRope.uf=ufBox.IsChecked==true;bool ladder=ladderBox.IsChecked==true;if(item.ParentRope.ladder!=ladder){item.ParentRope.OnUserTouchedLadder();item.ParentRope.ladder=ladder;}}Close();}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
